import osimport chromadbclass VectorDatabase:    """Класс для управления локальной векторной БД проекта (ChromaDB)"""    def __init__(self, project_path):        self.project_path = project_path                # База данных физически хранится внутри папки конкретного проекта        self.db_dir = os.path.join(self.project_path, ".vibecoder", "vector_db")        os.makedirs(self.db_dir, exist_ok=True)                # PersistentClient сохраняет данные на диск (в SQLite), а не держит их только в ОЗУ        self.client = chromadb.PersistentClient(path=self.db_dir)                # Создаем или получаем "коллекцию" (аналог таблицы в SQL)        # hnsw:space = cosine означает, что мы используем Косинусное сходство для поиска похожих векторов        self.collection = self.client.get_or_create_collection(            name="codebase_index",            metadata={"hnsw:space": "cosine"}         )    def add_chunks(self, ids: list[str], embeddings: list[list[float]], texts: list[str], metadatas: list[dict]):        """        Массовое добавление или обновление кусков кода в базе.        Метод upsert сам понимает: если ID уже есть - обновляем, если нет - создаем.        """        if not ids:            return                    self.collection.upsert(            ids=ids,            embeddings=embeddings,            documents=texts,            metadatas=metadatas        )    def search(self, query_embedding: list[float], n_results: int = 5):        """Семантический поиск по вектору вопроса"""        if self.collection.count() == 0:            return []                    # Защита: не просим больше результатов, чем есть в базе        limit = min(n_results, self.collection.count())                    results = self.collection.query(            query_embeddings=[query_embedding],            n_results=limit        )                # Форматируем сырой ответ ChromaDB в удобный список словарей        formatted_results = []        if results and results.get('documents') and results['documents'][0]:            for i in range(len(results['documents'][0])):                formatted_results.append({                    "id": results['ids'][0][i],                    "text": results['documents'][0][i],                    "metadata": results['metadatas'][0][i],                    "distance": results['distances'][0][i] if 'distances' in results and results['distances'] else 0.0                })        return formatted_results    def get_indexed_files(self) -> dict:        """Возвращает словарь {file_path: md5_hash} для всех проиндексированных файлов"""        if self.collection.count() == 0:            return {}                    results = self.collection.get(include=["metadatas"])        files = {}        if results and results.get("metadatas"):            for meta in results["metadatas"]:                if meta and "file_path" in meta:                    path = meta["file_path"]                    # Сохраняем хэш, если он есть                    if path not in files:                        files[path] = meta.get("md5_hash", "")        return files    def delete_file_chunks(self, file_path: str):        """Удаляет все векторы, связанные с конкретным файлом (для обновления)"""        if self.collection.count() == 0:             return        try:            self.collection.delete(where={"file_path": file_path})        except Exception:            pass    def get_all_files_stats(self) -> dict:        """Собирает подробную статистику для окна аналитики RAG"""        if self.collection.count() == 0:             return {}                    results = self.collection.get(include=["metadatas"])        stats = {}        if results and results.get("metadatas"):            for meta in results["metadatas"]:                if meta and "file_path" in meta:                    path = meta["file_path"]                    if path not in stats:                        stats[path] = {                            "chunk_count": 0,                            "md5_hash": meta.get("md5_hash", "Нет хэша"),                            "last_indexed": meta.get("last_indexed", "Неизвестно")                        }                    stats[path]["chunk_count"] += 1        return stats    def clear_database(self):        """Полная очистка базы (например, при смене провайдера эмбеддингов или принудительном сбросе)"""        try:            self.client.delete_collection("codebase_index")            self.collection = self.client.get_or_create_collection(                name="codebase_index",                metadata={"hnsw:space": "cosine"}            )        except ValueError:            pass